# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import os
from typing import Any, Dict, Optional

import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_SUBJECTS = {
    "info": "Information Notification",
    "warning": "Warning Notification",
    "error": "Error Notification",
    "success": "Success Notification",
    "event": "Event Notification",
}


def build_subject(notification_type: Optional[str], event: Dict[str, Any]) -> str:
    if event.get("subject"):
        return str(event["subject"])[:100]
    return DEFAULT_SUBJECTS.get(str(notification_type).lower(), "Notification")[:100]


def build_message(notification_type: Optional[str], message: Any, event: Dict[str, Any]) -> str:
    if isinstance(message, (dict, list)):
        payload = {
            "type": notification_type or "event",
            "message": message,
            "metadata": event.get("metadata", {}),
            "source": event.get("source", "lambda"),
        }
        return json.dumps(payload, default=str)
    return str(message)


def publish_to_sns(topic_arn: str, message: str, subject: str, attributes: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    params: Dict[str, Any] = {
        "TopicArn": topic_arn,
        "Message": message,
        "Subject": subject,
    }

    if attributes:
        message_attributes = {}
        for key, value in attributes.items():
            if value is None:
                continue
            message_attributes[str(key)] = {
                "DataType": "String",
                "StringValue": str(value),
            }
        if message_attributes:
            params["MessageAttributes"] = message_attributes

    response = sns.publish(**params)
    return {
        "message_id": response.get("MessageId"),
        "topic_arn": topic_arn,
        "subject": subject,
    }


def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    try:
        topic_arn = event.get("topic_arn") or os.environ.get("DEFAULT_SNS_TOPIC_ARN")
        if not topic_arn:
            return {
                "statusCode": 400,
                "body": json.dumps({"error": "Missing topic_arn in event or DEFAULT_SNS_TOPIC_ARN environment variable"}),
            }

        message = event.get("message")
        if message is None:
            return {
                "statusCode": 400,
                "body": json.dumps({"error": "Missing message in event"}),
            }

        notification_type = event.get("notification_type", "event")
        subject = build_subject(notification_type, event)
        formatted_message = build_message(notification_type, message, event)

        attributes = {
            "notification_type": notification_type,
            "source": event.get("source", "event-notification-system"),
            "environment": event.get("environment", os.environ.get("ENVIRONMENT", "unknown")),
        }

        result = publish_to_sns(
            topic_arn=topic_arn,
            message=formatted_message,
            subject=subject,
            attributes=attributes,
        )

        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "status": "published",
                    "result": result,
                }
            ),
        }

    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Failed to publish message to SNS",
                    "details": str(e),
                }
            ),
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Unexpected error",
                    "details": str(e),
                }
            ),
        }